INSERT INTO `rex_module` (`id`, `key`, `name`, `output`, `input`, `createdate`, `createuser`, `updatedate`, `updateuser`, `attributes`, `revision`) VALUES
(1,	NULL,	'* 99 - Weiterleitung zu Kindartikel',	'<?php\nif(!rex::isBackend()) {\n    $cat = rex_article::get($this->getValue(\"id\"))->getCategory();\n    if($cat) {\n        $children = $cat->getChildren();\n        if(count($children)>=1){\n            $kid = $children[0];\n            rex_response::setStatus(rex_response::HTTP_MOVED_PERMANENTLY);\n            rex_response::sendRedirect(rex_getUrl($kid->getId()));\n        }\n    }\n}\n?>',	'',	'2016-08-22 17:23:05',	'16massif',	'2023-11-30 14:08:52',	'console',	NULL,	0),
(2,	NULL,	'* 99 - Weiterleitung (intern/extern)',	'<?php\nif(!rex::isBackend()) {\n    if(\"REX_LINK[1]\") {\n        rex_response::setStatus(rex_response::HTTP_MOVED_PERMANENTLY);\n        rex_response::sendRedirect(rex_getUrl(\"REX_LINK[1]\"));\n    } else if(\"REX_VALUE[id=1]\"){\n        rex_response::sendRedirect(\"REX_VALUE[id=1]\");\n    }\n} else {\n    $link = (\"REX_LINK[1]\") ? rex_getUrl(\"REX_LINK[1]\") : \"REX_VALUE[id=1]\";\n    echo \'<p>Weiterleitung zu <b>\'.$link.\'</b></p>\';\n}\n?>',	'<?php\n\n// this modul input example use the mform addon\n\n// base ID\n$id = 1;\n\n// init mform\n$mform = MForm::factory();\n\n$mform->addFieldsetArea(\'intern\');\n\n$mform->addLinkField(1, array(\'label\' => \'Interner-Link\')); // use string for x.0 json values\n\n$mform->addFieldsetArea(\'extern\');\n\n$mform->addTextField(1, array(\'label\' => \'Externer-Link\')); // use string for x.0 json values\n\necho $mform->show();\n',	'2016-08-22 17:23:05',	'16massif',	'2023-11-30 14:08:52',	'console',	NULL,	0),
(3,	NULL,	'* 00 - Text-Block',	'<?php\n$buttons = [[\'url\' => \'REX_VALUE[19]\', \'label\' => \'<span>\' . \'REX_VALUE[20]\' . \'</span>\', \'style\' => \'grid\']];\n\n?>\n<section class=\"page-margin section-x-padding section-y-padding default-content<?= massif_utils::isFirstLastSlice(\'REX_SLICE_ID\') ?>\">\n\n    <?php if (\'REX_VALUE[1]REX_VALUE[2]\') { ?>\n        <div class=\"prose md:max-w-prose\">\n            <?= massif_utils::getH1(\'REX_VALUE[1]\') ?>\n            REX_VALUE[2 output=html]\n        </div>\n    <?php } ?>\n\n    <?= massif_img::get(\'REX_MEDIA[1]\', [\'width\' => \'1216\', \'classes\' => \'REX_VALUE[1]REX_VALUE[2]\' ? [\'mt-4 md:mt-8\'] : []]) ?>\n\n    <?php if (\'REX_VALUE[19]REX_VALUE[20]\') { ?>\n        <div class=\"prose<?php if (\'REX_VALUE[1]REX_VALUE[2]REX_MEDIA[1]\') { ?> mt-8 md:mt-16<?php } ?>\">\n            <?= massif_utils::getCustomLinks($buttons) ?>\n        </div>\n    <?php } ?>\n\n</section>',	'<?php\n\nerror_reporting(~E_DEPRECATED);\n\nuse FriendsOfRedaxo\\MForm;\n\n$mformWrap = MForm::factory();\n$mformWrap->addTextareaField(1, [\'label\' => \'Titel\'])->setAttribute(\"rows\", 2)->setAttribute(\"style\", \"font-size: 2em; line-height: 1;\");\n$mformWrap->addTextareaField(2, [\'label\' => \'Text\'])->setAttribute(\"rows\", 3)->setAttribute(\"class\", \"tiny-editor\")->setAttribute(\"data-profile\", \"massif\");\n$mformWrap->addMediaField(1, array(\'label\' => \'Bild\'));\n\n$mformWrap->addHtml(\'<div style=\"margin-top: 4em;\"></div>\');\n$mformWrap->addHtml(\'<div style=\"display: grid; grid-template-columns: 1.5fr 1fr; gap: 10px;\">\');\n// $ylink = [[\'name\' => \'Film\', \'table\' => \'rex_yf_film\', \'column\' => \'title_original\']];\n$mformWrap->addCustomLinkField(19, array(\'label\' => \'Button-Link\'));\n$mformWrap->addTextField(20, array(\'label\' => \'Button-Text\'));\n$mformWrap->addHtml(\'</div>\');\n\n\necho $mformWrap->show();\n',	'2021-06-25 13:30:54',	'admin',	'2024-02-29 12:52:23',	'console',	NULL,	0),
(4,	NULL,	'* 35 - Kontaktformular',	'<?php\n\n\n$tag = \'h1\';\nif (rex::getProperty(\'has-text-block\')) {\n    $tag = \'h3\';\n}\n\nrex::setProperty(\'has-text-block\', true);\n?>\n\n<div class=\"page-margin row-padding row-prose\">\n\n    <div class=\"wrap\">\n        <?php if (\'REX_VALUE[1]\') { ?><h1>REX_VALUE[1]</h1><?php } ?>\n        <div class=\"contact-grid\">\n            <div class=\"contact-grid__address\">\n                REX_VALUE[2 output=html]\n            </div>\n            <div class=\"contact-grid__form\">\n                <h3>Anfrageformular</h3>\n                <?php\n                echo massif_utils::parse(\'massif-form-general\', [\'response\' => \'REX_VALUE[4 output=html]\']);\n                ?>\n            </div>\n        </div>\n    </div>\n\n</div>',	'<?php\n\n\nuse FriendsOfRedaxo\\MForm;\n\n$mformWrap = MForm::factory();\n\n\n$mformWrap->addTextareaField(1, [\'label\' => \'Titel\'])->setAttribute(\"rows\", 3);\n$mformWrap->addTextareaField(2, [\'label\' => \'Text\'])->setAttribute(\"rows\", 8)->setAttribute(\"class\", \"tiny-editor\")->setAttribute(\"data-profile\", \"massif\");\n$mformWrap->addTextareaField(3, [\'label\' => \'Formular-Code Tally\'])->setAttribute(\"rows\", 10);\n$mformWrap->addTextareaField(4, [\'label\' => \'Text nach Versand\'])->setAttribute(\"rows\", 8)->setAttribute(\"class\", \"tiny-editor\")->setAttribute(\"data-profile\", \"massif\");\n\necho $mformWrap->show();\n\n?>\n<?= massif_utils::getModuleInJsCss() ?>\n',	'2022-04-28 18:15:53',	'admin',	'2023-11-30 14:08:52',	'console',	NULL,	0),
(5,	NULL,	'* 05 - Swiper',	'<?php\nrex::setProperty(\'has-visual\', true);\n\n$slides = explode(\',\', \'REX_MEDIALIST[1]\');\nshuffle($slides);\n$slides = array_slice($slides, 0, 7);\n$swiperHtml = [];\nforeach ($slides as $idx => $slide) {\n    $content = [];\n    $content[] = massif_img::get($slide, [\'width\' => 1999, \'loading\' => $idx == 0 ? \'eager\' : \'lazy\']);\n    $swiperHtml[] = massif_utils::parse(\'massif-swiper-slide\', [\'idx\' => $idx, \'content\' => implode(\"\\n\", $content)]);\n}\n\n?>\n\n<div class=\"swiper swiper-fs\">\n    <?php\n    echo massif_img::getSwiper([\'content\' => implode(\"\\n\", $swiperHtml), \'controls\' => false, \'dir-nav\' => false, \'pager\' => false]);\n    ?>\n</div>',	'<?php\n\nerror_reporting(~E_DEPRECATED);\n\nuse FriendsOfRedaxo\\MForm;\n\n$mformWrap = MForm::factory();\n$mformWrap->addImageListField(1, array(\'label\' => \'Bilder\'));\n// $mformWrap->addCheckboxField(10, array(\'label\' => \'Schmale Darstellung\'));\n// $mformWrap->addCheckboxField(11, array(\'label\' => \'Im Raster anzeigen?\'));\n\n// $mformWrap->addTextField(1, array(\'label\' => \'Spitzmarke\'));\n\n// \n\n// \n/*\n$id = 1;\n$mform = MForm::factory();\n$mform->addMediaField(1, array(\'label\' => \'Bild\'));\n$mform->addTextareaField(\"$id.0.title\", array(\'label\' => \'Titel\'))->setAttribute(\"rows\", 2);\n$mform->addTextareaField(\"$id.0.body\", array(\'label\' => \'Text\'))->setAttribute(\"rows\", 4)->setAttribute(\"class\", \"tinyMCEEditor-massif\");\n$mform->addHtml(\'<div class=\"flexed col-2\">\');\n$ylink = [[\'name\' => \'Film\', \'table\' => \'rex_yf_film\', \'column\' => \'title_original\']];\n$mform->addCustomLinkField(\"$id.0.link\", array(\'label\' => \'Button-Link\', \'ylink\' => $ylink));\n$mform->addTextField(\"$id.0.btnlabel\", array(\'label\' => \'Button-Text\'));\n$mform->addHtml(\'</div>\');\n\n$mformWrap->addHtml(MBlock::show($id, $mform->show(), array(\'min\' => 1)));\n*/\n/*\n$mformWrap->addSelectField(5, [0 => \'Mitte\', \'top\' => \'oben\', \'bottom\' => \'unten\'], array(\'label\' => \'Bild-Ausrichtung\'));\n$mformWrap->addHtml(\'<div class=\"alert alert-info\">Vertikale Bildausrichtung</div>\');\n*/\n\necho $mformWrap->show();\n',	'2022-07-25 18:13:23',	'admin',	'2024-02-08 16:49:54',	'console',	NULL,	0);
INSERT INTO `rex_template` (`id`, `key`, `name`, `content`, `active`, `createdate`, `createuser`, `updatedate`, `updateuser`, `attributes`, `revision`) VALUES
(1,	'default',	'* Default',	'REX_TEMPLATE[key=\"config\"]\r\n\r\nREX_TEMPLATE[key=\"html-head\"]\r\n\r\n<body class=\"<?= $pageClass ?> bg-white text-primary font-sans\">\r\n\r\n	REX_TEMPLATE[key=\"header\"]\r\n\r\n	<div class=\"content-wrap\">\r\n		<main role=\"main\" class=\"content content-main\" id=\"content\" data-sp=\"<?= rex_getUrl(rex_article::getSiteStartArticleId()); ?>\" data-lang-code=\"<?= rex_clang::getCurrent()->getCode() ?>\" data-logo-href=\"<?= rex_getUrl(rex_article::getSiteStartArticleId()) ?>\">\r\n			{REDAXO_LOGIN_DATA}<?php\r\n			$articleContent = $this->getArticle(1);\r\n			echo $articleContent;\r\n			?>\r\n		</main>\r\n	</div>\r\n\r\n	REX_TEMPLATE[key=\"footer\"]\r\n\r\n	REX_TEMPLATE[key=\"html-scripts\"]\r\n\r\n</body>\r\n<?php if (!rex::getProperty(\'req-with\')) echo \'</html>\'; ?>',	1,	'2024-01-09 16:13:37',	'admin',	'2024-02-02 21:09:51',	'admin',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(2,	'html-scripts',	'HTML Scripts',	'<script>\r\n  window.lazySizesConfig = window.lazySizesConfig || {};\r\n  const app = {\r\n    lang: {\r\n      \'code\': \'<?= rex_clang::getCurrent()->getValue(\'code\') ?>\',\r\n      \'weiterlesen\': \"{{mehr}}\",\r\n      \'keineTreffer\': \"{{keine Suchtreffer}}\"\r\n    }\r\n  };\r\n</script>\r\n<?= \\Ynamite\\ViteRex\\ViteRex::getAssets() ?>',	0,	'2024-01-09 16:15:15',	'admin',	'2024-02-12 11:09:57',	'console',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(3,	'config',	'Config',	'<?php\r\n\r\nheader(\'Content-Type: text/html; charset=utf-8\');\r\nrex::setProperty(\'req-with\', isset($_SERVER[\'HTTP_X_REQUESTED_WITH\']) && $_SERVER[\'HTTP_X_REQUESTED_WITH\'] && $_SERVER[\'HTTP_X_REQUESTED_WITH\'] == \'swup\');\r\n\r\n/*\r\n	*	config\r\n	*/\r\n\r\n// get current language and locale\r\n$lang = rex_clang::getCurrent();\r\n$langLocale = $lang->getValue(\'locale\');\r\n\r\n$isMobileOrTablet = \' browser-is-\' . rex_string::normalize(useragent::getBrowser());\r\n\r\nif (useragent::isTablet()) {\r\n	$isMobileOrTablet .= \' is-tablet\';\r\n} else if (useragent::isMobile()) {\r\n	$isMobileOrTablet .= \' is-mobile\';\r\n}\r\nif (useragent::isBrowserEdge()) {\r\n	$isMobileOrTablet .= \' is-edge\';\r\n}\r\nif (useragent::isBrowserInternetExplorer()) {\r\n	$isMobileOrTablet .= \' is-ie\';\r\n}\r\n\r\n// get current path route (category-id depth)\r\n$pathRoute = massif_utils::getPathRoute();\r\n$pageClass = \'page-id-\' . rex_article::getCurrentId();\r\n$pageClass .= \' page-pid-\' . $pathRoute[0];\r\n\r\n$currentArticle = rex_article::getCurrent();\r\n$tmplId = $currentArticle->getTemplateId();\r\n$pageClass .= \' tmpl-id-\' . $tmplId;\r\n\r\n$manager = Url\\Url::resolveCurrent();\r\nif ($manager) {\r\n	$urlManagerData = [];\r\n	if ($profile = $manager->getProfile()) {\r\n		$ns = $profile->getNamespace();\r\n		$urlManagerData[$ns] = [];\r\n		$urlManagerData[$ns][\'url\'] = $manager->getUrl()->getPath();\r\n		$urlManagerData[$ns][\'id\'] = $manager->getDatasetId();\r\n		$urlManagerData[$ns][\'ns-id\'] = $profile->getId();\r\n		$urlManagerData[$ns][\'ns\'] = $profile->getNamespace();\r\n		$urlManagerData[$ns][\'table-name\'] = $profile->getTableName();\r\n		$pageClass .= \' url-manager-page url-profile-\' . $profile->getNamespace();\r\n		if ($manager->isUserPath()) {\r\n			$segments = $manager->getUrl()->getSegments();\r\n			foreach ($profile->getUserPaths() as $value => $label) {\r\n				if (in_array($value, $segments)) {\r\n					$urlManagerData[$ns][\'user-path\'] = $label;\r\n				}\r\n			}\r\n		}\r\n	}\r\n	rex::setProperty(\'url-manager-data\', $urlManagerData);\r\n}\r\n$pageClass .= (massif_utils::isStartPage()) ? \' home-page\' : \' content-page\';\r\n',	0,	'2024-01-09 16:11:00',	'admin',	'2024-02-12 11:08:38',	'console',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(5,	'html-head',	'HTML Head',	'<!doctype html>\r\n<?php\r\n$xmlns = \' xmlns:fb=\"http://www.facebook.com/2008/fbml\" xmlns:og=\"http://opengraphprotocol.org/schema/\"\';\r\n?>\r\n<html class=\"js<?= $isMobileOrTablet ?>\" lang=\"<?= $lang->getCode() ?>\" <?= $xmlns; ?>>\r\n\r\n<head>\r\n    REX_TEMPLATE[key=\"html-meta\"]\r\n</head>',	0,	'2024-01-09 16:12:46',	'admin',	'2024-01-09 16:30:57',	'admin',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(6,	'html-meta',	'HTML Meta',	'<!--\r\n          \r\n          Website by\r\n             __    __  ______  ______  ______  __  ______  \r\n            /\\ \"-./  \\/\\  __ \\/\\  ___\\/\\  ___\\/\\ \\/\\  ___\\ \r\n            \\ \\ \\-./\\ \\ \\  __ \\ \\___  \\ \\___  \\ \\ \\ \\  __\\ \r\n             \\ \\_\\ \\ \\_\\ \\_\\ \\_\\/\\_____\\/\\_____\\ \\_\\ \\_\\/   \r\n              \\/_/  \\/_/\\/_/\\/_/\\/_____/\\/_____/\\/_/\\/_/   \r\n        \r\n               https://www.massif.ch\r\n        \r\n-->\r\n<?php\r\n// $speed_up = new speed_up();\r\n// $speed_up->show();\r\n?>\r\n\r\n<meta charset=\"utf-8\" />\r\n<meta http-equiv=\"content-type\" content=\"text/html; charset=utf-8\" />\r\n<meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\" />\r\n\r\n<?= massif_seo::getTags() ?>\r\n\r\n<?php /* Ynamite\\MassifSettings\\Utils::getFaviconHtml() */ ?>\r\nREX_TEMPLATE[key=\"html-favicon\"]\r\n\r\n<?php if (!rex::getProperty(\'req-with\')) { ?>\r\n\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\r\n\r\n    <?= \\Ynamite\\ViteRex\\ViteRex::getCriticalCss() ?>\r\n\r\n    <?php if (!rex::isDebugMode()) { ?>\r\n    <?php } ?>\r\n\r\n<?php } ?>',	0,	'2024-02-15 07:09:30',	'admin',	'2024-02-15 11:02:37',	'console',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(7,	'footer',	'* Footer',	'<?php\r\n$settings = rex_config::get(\'massif_settings\');\r\n?>\r\n<footer id=\"footer\" class=\"footer section-p lg:grid lg:grid-cols-2 xl:grid-cols-4 lg:~gap-x-10/20 links-underlined-i\">\r\n	<div>\r\n		<div>{{address_firma}}</div>\r\n		<?php if (isset($settings[\'address_zusatz\']) && $settings[\'address_zusatz\']) { ?>\r\n			<div>{{address_zusatz}}</div>\r\n		<?php } ?>\r\n	</div>\r\n	<div>\r\n		<?php if (isset($settings[\'address_phone\']) && $settings[\'address_phone\']) { ?>\r\n			<div>T {{address_phone_html}}</div>\r\n		<?php } ?>\r\n		<?php if (isset($settings[\'address_e_mail\']) && $settings[\'address_e_mail\']) { ?>\r\n			<div>{{address_e-mail_html}}</div>\r\n		<?php } ?>\r\n	</div>\r\n	<div>\r\n		<?= massif_nav::articles() ?>\r\n	</div>\r\n	<div>\r\n		<?php if (isset($settings[\'social_instagram\']) && $settings[\'social_instagram\']) { ?>\r\n			<div>\r\n				<a href=\"{{social_instagram}}\" target=\"_blank\">Instagram</a>\r\n			</div>\r\n		<?php } ?>\r\n		<?php if (isset($settings[\'social_linkedin\']) && $settings[\'social_linkedin\']) { ?>\r\n			<div>\r\n				<a href=\"{{social_linkedin}}\" target=\"_blank\">LinkedIn</a>\r\n			</div>\r\n		<?php } ?>\r\n	</div>\r\n</footer>',	0,	'2024-01-09 16:17:19',	'admin',	'2025-02-28 10:30:24',	'admin',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(8,	'header',	'* Header',	'<?php\r\n\r\n$nav = massif_nav::factory();\r\n$nav->addFilter(\'id\', 1, \'!=\', 1);\r\n$nav->addCallback(function ($cat, $depth, &$li, &$a, &$name) {\r\n	$a[\'title\'] = $cat->getName();\r\n	$name = \'<span>\' . $name . \'</span>\';\r\n	// if ($depth == 1) {\r\n	// 	if (count($cat->getChildren()) > 0) {\r\n	// 		$li[\'class\'][] = \'has-dropdown\';\r\n	// 		$name = \'<span>\' . $name . \'</span><i class=\"icon fa fa-chevron-down\"></i>\';\r\n	// 	}\r\n	// }\r\n\r\n	// if ($depth == 1) {\r\n	// 	if (count($cat->getChildren()) > 0) {\r\n	// 		$li[\'class\'][] = \'has-dropdown\';\r\n	// 	}\r\n	// }\r\n\r\n	return true;\r\n});\r\n\r\n$pathRoute = massif_utils::getPathRoute();\r\n\r\n\r\n$isPopup = rex_request(\'popup\', \'bool\', false);\r\n$params = [];\r\nif ($_GET) {\r\n	if (isset($_GET[\'popup\'])) {\r\n		unset($_GET[\'popup\']);\r\n	}\r\n	foreach ($_GET as $key => $val) {\r\n		$params[$key] = $val;\r\n	}\r\n}\r\n\r\n\r\n?>\r\n<a id=\"top\"></a>\r\n\r\n<header class=\"header header section-px py-4 flex\" id=\"header\">\r\n\r\n	<div class=\"site-logo ~w-40/52\">\r\n		<a href=\"<?= rex_getUrl(rex_article::getSiteStartArticleId()); ?>\" title=\"<?= rex::getServerName() ?>\">\r\n			<span hidden><?= rex::getServerName() ?></span>\r\n			<?= \\Ynamite\\ViteRex\\ViteRex::getImg(\'massif-logo.svg\') ?>\r\n		</a>\r\n	</div>\r\n\r\n	<a href=\"<?= rex_getUrl(rex_article::getCurrentId()) ?>#content\" data-scroll class=\"to-content\" title=\"Zum Inhalt\"><span hidden>Zum Inhalt</span></a>\r\n\r\n	<div id=\"menus\">\r\n\r\n		<?php if (!$isPopup) { ?>\r\n\r\n			<div class=\"menu main-menu\" data-menu-desktop data-menu-id=\"main-menu\">\r\n\r\n				<nav class=\"main-nav\">\r\n					<?= $nav->get(0, 1, false, true) ?>\r\n				</nav>\r\n\r\n			</div>\r\n		<?php } ?>\r\n\r\n	</div>\r\n\r\n</header>',	0,	'2024-01-09 16:18:04',	'admin',	'2024-01-26 15:11:13',	'admin',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0),
(9,	'modal',	'* Default Modal/Overlay',	'<?php \nrequire(theme_path::base(\"private/template/view-set.php\"));\n',	1,	'2021-06-18 19:36:38',	'admin',	'2023-11-30 14:08:52',	'console',	'{\"ctype\":[],\"modules\":{\"1\":{\"0\":\"163\",\"all\":0}},\"categories\":{\"all\":\"1\"}}',	0),
(10,	'mjml',	'MJML/Mail',	'<?php ob_start(); ?>\n<mjml>\n  <mj-head>\n        <mj-preview><?=rex::getServer();?></mj-preview>\n	\n        <mj-attributes>\n          <mj-all font-family=\"Arial, sans-serif\" />\n        </mj-attributes>\n		<mj-breakpoint width=\"730px\" />\n		<mj-style>\n	      .bg-white table {\n	        background-color: #ffffff !important;\n	      }\n	      \n	        \n		  @media (max-width:580px) { \n	        .sectionpadded  table:first-child > td:first-child  {\n	          padding-left:20px !important;\n	          padding-right:20px;\n	        }\n	      }\n	      \n	    </mj-style>\n	    \n	\n	\n\n  </mj-head>\n  <mj-body background-color=\"#F4F4F4\">\n  \n 	<mj-wrapper width=\"600px\" background-color=\"#F4F4F4\" padding=\"40px\">\n		<mj-wrapper padding=\"0\" >\n			\n			<mj-section background-color=\"#fff\" css-class=\"sectionpadded\" padding=\"40px 40px 40px 40px\">\n		      <mj-column padding=\"0\">\n		        <mj-image width=\"254\" padding=\"0\" align=\"left\" src=\"<?=rex_url::assets(\'theme/img/logo-vzf.png\')?>\" href=\"<?=rex_yrewrite::getCurrentDomain()?>\" />\n\n		      </mj-column>\n		    </mj-section>\n			\n			REX_ARTICLE[]\n			\n			<mj-section padding=\"40px 0\" css-class=\"sectionpadded\"  background-color=\"#202020\">\n			    <mj-column>\n			\n				\n					<mj-text align=\"left\" \n							 font-weight=\"normal\"\n							 font-size=\"14px\"\n							 line-height=\"20px\" \n							 color=\"#fff\"\n							 padding=\"0 40px\">\n							<b>{{address_firma}}<br />\n							{{address_firma_zusatz}}</b><br />\n							{{address_strasse}}<br />\n							{{address_plz}} {{address_ort}}<br /><br />\n							{{address_telefon_html}}<br>\n							{{address_fax_html}}<br>\n							{{address_e-mail_html}}<br>\n\n					</mj-text>\n					\n			    </mj-column>\n			</mj-section>\n		\n		</mj-wrapper>\n 	</mj-container>\n   \n  </mj-body>\n</mjml>\n<?php \n	\n	$mjml = ob_get_clean();\n\n	if(isset($_GET[\'mjml\']))	\n		die($mjml);\n		\n	$user = \'5db3a909-efbb-48e6-adee-50b88bbc0f22\';\n	$pwd = \'49ca4f4f-11b1-4940-b3b1-b520725d519e\';\n	\n	$mjmlClient = new mjmlClient($user, $pwd);\n	\n	\n	$response = $mjmlClient->render($mjml);\n	\n	\n	\n	echo $response;\n\n?>\n',	0,	'2021-06-16 16:49:01',	'admin',	'2023-11-30 14:08:52',	'console',	'{\"ctype\":[],\"modules\":{\"1\":{\"0\":\"151\",\"1\":\"157\",\"2\":\"156\",\"all\":0}},\"categories\":{\"all\":\"1\"}}',	0),
(11,	'html-favicon',	'HTML Favicon',	'<link rel=\"apple-touch-icon\" sizes=\"180x180\" href=\"/apple-touch-icon.png\">\r\n<link rel=\"icon\" type=\"image/png\" sizes=\"32x32\" href=\"/favicon-32x32.png\">\r\n<link rel=\"icon\" type=\"image/png\" sizes=\"16x16\" href=\"/favicon-16x16.png\">\r\n<link rel=\"manifest\" href=\"/site.webmanifest\">\r\n<link rel=\"mask-icon\" href=\"/safari-pinned-tab.svg\" color=\"#7a7256\">\r\n<meta name=\"msapplication-TileColor\" content=\"#ebeae6\">\r\n<meta name=\"theme-color\" content=\"#ebeae6\">\r\n<link rel=\"icon\" type=\"image/ico\" href=\"/favicon.ico\">\r\n<meta name=\"msapplication-config\" content=\"browserconfig.xml\" />\r\n',	0,	'2024-02-15 11:03:06',	'admin',	'2024-02-15 11:03:06',	'admin',	'{\"ctype\":[],\"modules\":{\"1\":{\"all\":\"1\"}},\"categories\":{\"all\":\"1\"}}',	0);
INSERT INTO `rex_tinymce_profiles` (`id`, `name`, `description`, `plugins`, `toolbar`, `extra`, `mediatype`, `mediapath`, `mediacategory`, `upload_default`, `createdate`, `updatedate`, `createuser`, `updateuser`) VALUES
(1,	'massif',	'custom',	NULL,	NULL,	'language: \'de\',\r\ntoolbar_location: \'bottom\',\r\nbranding: false,\r\nstatusbar: true,\r\nmenubar: false,\r\nrelative_urls : false,\r\nremove_script_host : true,\r\ndocument_base_url : \"/\",\r\nconvert_urls : true,\r\nplugins: \'autoresize searchreplace autolink directionality visualblocks visualchars fullscreen image link media charmap hr pagebreak nonbreaking anchor toc lists wordcount imagetools textpattern help paste code \' +\r\n    \'save\' +\r\n    \'\',\r\ntoolbar: \'formatselect styleselect removeformat | undo redo | bold italic subscript superscript | link image media | align alignleft aligncenter alignright | numlist bullist outdent indent | code | fullscreen | visualchars | searchreplace | cut copy paste pastetext selectall wordcount charmap nonbreaking anchor toc\',\r\n\r\nblock_formats:  \'Titel  H1=h1;  Titel  H2=h2;  Titel  H3=h3;  Titel  H4=h4;  Absatz=p\',\r\nstyle_formats:  [\r\n    //{title:  \'Elemente\',  items:  [\r\n        {title:  \'wie  H1\',  format: \'s_h1\' },\r\n        {title:  \'wie  H2\', format: \'s_h2\' },\r\n        {title:  \'wie  H3\', format: \'s_h3\' },\r\n        {title:  \'wie  H4\', format: \'s_h4\' },\r\n        {title:  \'Lead\', format: \'s_lead\' },\r\n        {title:  \'wie  Absatz  /  Text  normal\', format: \'s_p\' },\r\n        {title:  \'klein\', format: \'text_small\' },\r\n    //]}\r\n],\r\nformats:{\r\n    s_h1: { selector:  \'h1,h2,h3,h4,p,div\',  classes:  \'h1\' },\r\n    s_h2: { selector:  \'h1,h2,h3,h4,p,div\',  classes:  \'h2\' },\r\n    s_h3: { selector:  \'h1,h2,h3,h4,p,div\',  classes:  \'h3\' },\r\n    s_h4: { selector:  \'h1,h2,h3,h4,p,div\',  classes:  \'h3\' },\r\n    s_lead: { selector:  \'h1,h2,h3,h4,p,div\',  classes:  \'lead\' },\r\n    s_p: { selector:  \'h1,h2,h3,h4,p,div\', classes:  \'text-normal\' },\r\n    text_small: { inline: \'span\', selector:  \'h1,h2,h3,h4,p,div,span\', classes:  \'text-small\' },\r\n    text_rotated: { selector:  \'h1,h2,h3,h4,p,div\', classes:  \'text-rotated\' },\r\n    font_mono: { selector:  \'h1,h2,h3,h4,p,div\', classes:  \'font-mono\' },\r\n    colorquad: { inline: \'em\', selector:  \'h1,h2,h3,h4,p,div,span\', classes:  \'color-quad\' },\r\n    weight_light: { inline: \'span\', selector:  \'h1,h2,h3,h4,p,div,span\', classes:  \'weight-light\' },\r\n    weight_medium: { inline: \'span\', selector:  \'h1,h2,h3,h4,p,div,span\', classes:  \'weight-medium\' },\r\n},\r\ncontent_style:  \'\'+\r\n    \'.h1{font-size:34px}\'+\r\n    \'.text-large{font-size:31px}\'+\r\n    \'.h2{font-size:28px}\'+\r\n    \'.h3,.lead{font-size:24px}\'+\r\n    \'.h4{font-size:18px}\'+\r\n    \'.lead{font-size:20px; font-weight: 500;}\'+\r\n    \'p{color: #000;font-size:18px;}\'+\r\n    \'.text-small{font-size:14px;}\'+\r\n    \'.color-quad{color: #077984;}\'+\r\n    \'.color-tert{color: #FFF3C1;}\'+\r\n    \'.weight-light{font-weight:300;}\'+\r\n    \'.weight-medium{font-weight:500;}\'+\r\n    \'.font-mono{font-family: \"Courier New\", Courier, monospace;}\'+\r\n    \'.text-rotated{transform: rotate(-8deg);}\'+\r\n    \'.text-normal{font-size:20px;font-weight:normal;}\'+\r\n    \'.text-small{font-size:16px;font-weight:normal;}\',\r\n    \r\n\r\nconvert_fonts_to_spans:  true,\r\n\r\nimage_caption: true,\r\nimage_uploadtab: false,\r\n// paste_as_text: true,\r\npowerpaste_word_import: \"clean\",\r\npowerpaste_html_import: \"merge\",\r\n\r\n// height: 700,\r\n\r\nvisualblocks_default_state: true,\r\n\r\ntoc_depth: 3,\r\ntoc_header: \"div\", // case doesn\'t matter\r\ntoc_class: \"our-toc\",\r\ntoolbar_sticky: true,\r\n\r\n// autoresize_bottom_margin: 5,\r\nfile_picker_callback: function (callback, value, meta) {\r\n    rex5_picker_function(callback, value, meta);\r\n}',	NULL,	NULL,	NULL,	NULL,	'2019-07-31 06:45:57',	'2023-12-06 17:07:07',	'admin',	'admin'),
